function calculate() {
  const dataExchangeProtocolCoverage = parseFloat(inputs.dataExchangeProtocolCoverage);
  const systemInteroperabilityIndex = parseFloat(inputs.systemInteroperabilityIndex);
  const cybersecurityFrameworkMaturity = parseFloat(inputs.cybersecurityFrameworkMaturity);
  const realTimeDataUtilization = parseFloat(inputs.realTimeDataUtilization);
  const citizenEngagementTechAdoption = parseFloat(inputs.citizenEngagementTechAdoption);
  const infrastructureConnectivityDensity = parseFloat(inputs.infrastructureConnectivityDensity);
  const openDataPolicyImplementation = parseFloat(inputs.openDataPolicyImplementation);
  const digitalTwinIntegrationLevel = parseFloat(inputs.digitalTwinIntegrationLevel);

  // Input validation and default to 0 if NaN (though 'required' should prevent this in UI)
  if (isNaN(dataExchangeProtocolCoverage) || isNaN(systemInteroperabilityIndex) || isNaN(cybersecurityFrameworkMaturity) || 
      isNaN(realTimeDataUtilization) || isNaN(citizenEngagementTechAdoption) || isNaN(infrastructureConnectivityDensity) ||
      isNaN(openDataPolicyImplementation) || isNaN(digitalTwinIntegrationLevel)) {
    return { integrationScore: 0 };
  }

  // Normalize 1-5 scale inputs to 0-100
  const normalizeScale = (value) => ((value - 1) / 4) * 100;

  const n_systemInteroperability = normalizeScale(systemInteroperabilityIndex);
  const n_cybersecurityMaturity = normalizeScale(cybersecurityFrameworkMaturity);
  const n_citizenEngagement = normalizeScale(citizenEngagementTechAdoption);
  const n_openDataPolicy = normalizeScale(openDataPolicyImplementation);
  const n_digitalTwin = normalizeScale(digitalTwinIntegrationLevel);

  // Normalize Infrastructure Connectivity Density
  // Assuming an ideal maximum density for a leading smart city might be around 2500 devices/km²
  // Cap this at 100% contribution even if density exceeds ideal for max score.
  const maxIdealDensity = 2500; 
  const n_connectivityDensity = Math.min(infrastructureConnectivityDensity / maxIdealDensity, 1) * 100;

  // Define weights for each input
  const weights = {
    dataExchangeProtocolCoverage: 0.20,
    systemInteroperabilityIndex: 0.20,
    cybersecurityFrameworkMaturity: 0.15,
    realTimeDataUtilization: 0.15,
    citizenEngagementTechAdoption: 0.10,
    infrastructureConnectivityDensity: 0.10,
    openDataPolicyImplementation: 0.05,
    digitalTwinIntegrationLevel: 0.05
  };

  // Calculate weighted score for each component
  const score_dataExchange = dataExchangeProtocolCoverage * weights.dataExchangeProtocolCoverage;
  const score_interoperability = n_systemInteroperability * weights.systemInteroperabilityIndex;
  const score_cybersecurity = n_cybersecurityMaturity * weights.cybersecurityFrameworkMaturity;
  const score_realTimeData = realTimeDataUtilization * weights.realTimeDataUtilization;
  const score_citizenEngagement = n_citizenEngagement * weights.citizenEngagementTechAdoption;
  const score_connectivity = n_connectivityDensity * weights.infrastructureConnectivityDensity;
  const score_openData = n_openDataPolicy * weights.openDataPolicyImplementation;
  const score_digitalTwin = n_digitalTwin * weights.digitalTwinIntegrationLevel;

  // Sum all weighted scores
  let totalScore = score_dataExchange + score_interoperability + 
                   score_cybersecurity + score_realTimeData + 
                   score_citizenEngagement + score_connectivity + 
                   score_openData + score_digitalTwin;

  // Ensure score is within 0-100 range
  totalScore = Math.max(0, Math.min(100, totalScore));

  return {
    integrationScore: totalScore
  };
}
